1	package com.fortinet.nac.ingestion.job;
2	
3	import com.fortinet.nac.ingestion.job.event.PolicyStatusChangedEvent;
4	import lombok.RequiredArgsConstructor;
5	import lombok.extern.slf4j.Slf4j;
6	import org.springframework.beans.factory.annotation.Qualifier;
7	import org.springframework.beans.factory.annotation.Value;
8	import org.springframework.context.event.EventListener;
9	import org.springframework.scheduling.annotation.Async;
10	import org.springframework.stereotype.Component;
11	import org.springframework.web.client.RestTemplate;
12	
13	import java.util.Map;
14	
15	@Slf4j
16	@Component
17	@RequiredArgsConstructor
18	public class PolicyStatusNotifier {
19	
20	    @Qualifier("policyNotifyRestTemplate")
21	    private final RestTemplate restTemplate;
22	
23	    @Value("${policy.service.url}")
24	    private String policyServiceUrl;
25	
26	    @Async("policyNotifyExecutor")
27	    @EventListener
28	    public void onStatusChanged(PolicyStatusChangedEvent event) {
29	        try {
30	            restTemplate.postForEntity(
31	                    policyServiceUrl + "/api/v1/internal/entity-status-changed",
32	                    Map.of(
33	                            "entityId", event.getEntityId(),
34	                            "stage", event.getStage(),
35	                            "fingerprint", event.getFingerprint()
36	                    ),
37	                    Void.class
38	            );
39	            log.debug("PolicyService notified, entityId={} stage={}", event.getEntityId(), event.getStage());
40	        } catch (Exception ex) {
41	            // Notification is best-effort; log and continue — never propagate back to Kafka consumer.
42	            log.warn("PolicyService notification failed, entityId={}: {}", event.getEntityId(), ex.getMessage());
43	        }
44	    }
45	}
