50	            if (!isAsync) {
51	                processingRegistry.register(entityId, requestId);
52	            }
53	
54	            while (true) {
55	                if (entityService.isInterrupted(entityId)) {
56	                    log.info("Entity {} processing interrupted.", entityId);
57	
58	                    resultTag = "interrupted";
59	                    return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_PROCESS_INTERRUPTED, "interrupted");
60	                }
61	
62	                String stageStr = entityDTO.getProcessingStage();
63	                if (stageStr == null) {
64	                    resultTag = "fail";
65	                    return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_INVALID_ENTITY_STAGE,
66	                            "processingStage is null for entityId=" + entityId);
67	                }
68	
69	                EntityStage stage = EntityStage.valueOf(stageStr.toUpperCase());
70	
71	                int code = entityDTO.getProcessingCode() == null ? 0 : entityDTO.getProcessingCode();
72	                if (code != 0) {
73	                    log.info("Entity {} failed in stage={}, code={}", entityId, stage, code);
74	
75	                    resultTag = "fail";
76	                    return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
77	                }
78	
79	                boolean success = false;
80	
81	                switch (stage) {
82	                    case PENDING:
83	                        success = handlePending(entityDTO);
84	                        break;
85	                    case LABELED:
86	                        success = handleLabeled(entityDTO);
87	                        break;
88	                    case EVALUATED:
89	                        success = handleEvaluated(entityDTO);
90	                        break;
91	                    case ENFORCED:
92	                        // completed
93	                        return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
94	                    default:
95	                        resultTag = "fail";
96	                        return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_INVALID_ENTITY_STAGE,
97	                                "Invalid stage: " + stage);
98	                }
99	
100	                if (!success) {

100	                if (!success) {
101	                    resultTag = "fail";
102	                    return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
103	                }
104	            }
105	        } finally {
106	            if (!isAsync) {
107	                processingRegistry.unregister(entityId);
108	            }
109	            log.info("State Machine cost {} ms", TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime));
110	
111	            String stageStr = entityDTO.getProcessingStage();
112	            String finalStageTag = (stageStr == null ? "UNKNOWN" : stageStr.toUpperCase());
113	
114	            Timer timer = Timer.builder("ingestion_state_machine_seconds")
115	                    .tag("result", resultTag)
116	                    .tag("finalStage", finalStageTag)
117	                    .register(meterRegistry);
118	            sample.stop(timer);
119	        }
120	    }
