15	
16	    @Value("${entity.reset.notify.core-size:1}")
17	    private int coreSize;
18	
19	    @Value("${entity.reset.notify.max-size:2}")
20	    private int maxSize;
21	
22	    // Bounded queue: drops notifications silently when full rather than blocking the publisher.
23	    @Value("${entity.reset.notify.queue-capacity:200}")
24	    private int queueCapacity;
25	
26	    @Value("${entity.reset.notify.connect-timeout-ms:100}")
27	    private int connectTimeoutMs;
28	
29	    @Value("${entity.reset.notify.read-timeout-ms:200}")
30	    private int readTimeoutMs;
31	
32	    @Bean("entityResetNotifyExecutor")
33	    public Executor entityResetNotifyExecutor() {
34	        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
35	        executor.setCorePoolSize(coreSize);
36	        executor.setMaxPoolSize(maxSize);
37	        executor.setQueueCapacity(queueCapacity);
38	        executor.setThreadNamePrefix("entity-reset-notify-");
39	        // DiscardPolicy: fire-and-forget — notifications are best-effort, never block the caller.
40	        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.DiscardPolicy());
41	        executor.initialize();
42	        return executor;
43	    }
44	
45	    @Bean("entityResetNotifyRestTemplate")
46	    public RestTemplate entityResetNotifyRestTemplate() {
47	        SimpleClientHttpRequestFactory factory = new SimpleClientHttpRequestFactory();
48	        factory.setConnectTimeout(connectTimeoutMs);
49	        factory.setReadTimeout(readTimeoutMs);
50	        return new RestTemplate(factory);
51	    }
