package com.fortinet.nac.ingestion.job;

import com.fortinet.nac.ingestion.job.event.EntityResetEvent;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.event.EventListener;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Component;
import org.springframework.web.client.RestTemplate;

import java.util.Map;

@Slf4j
@Component
@RequiredArgsConstructor
public class EntityResetNotifier {

    @Qualifier("entityResetNotifyRestTemplate")
    private final RestTemplate restTemplate;

    @Value("${entity.reset.notify.url}")
    private String notifyUrl;

    @Async("entityResetNotifyExecutor")
    @EventListener
    public void onEntityReset(EntityResetEvent event) {
        try {
            restTemplate.postForEntity(
                    notifyUrl + "/api/v1/internal/entity-reset",
                    Map.of("entityId", event.getEntityId()),
                    Void.class
            );
            log.debug("entity-reset notified, entityId={}", event.getEntityId());
        } catch (Exception ex) {
            // Notification is best-effort; log and continue — never propagate back to Kafka consumer.
            log.warn("entity-reset notification failed, entityId={}: {}", event.getEntityId(), ex.getMessage());
        }
    }
}

